// Sound effects using Web Audio API
const AC = typeof AudioContext !== "undefined" ? new AudioContext() : null;
const beep = (freq, dur, type="sine", vol=0.15) => {
  if (!AC) return;
  try {
    AC.resume();
    const o = AC.createOscillator();
    const g = AC.createGain();
    o.type = type;
    o.frequency.value = freq;
    g.gain.value = vol;
    g.gain.exponentialRampToValueAtTime(0.001, AC.currentTime + dur);
    o.connect(g);
    g.connect(AC.destination);
    o.start();
    o.stop(AC.currentTime + dur);
  } catch(e) {}
};
const sndClick = () => beep(800, 0.08, "sine", 0.1);
const sndOpen = () => { beep(523, 0.1); setTimeout(() => beep(659, 0.1), 80); setTimeout(() => beep(784, 0.12), 160); };
const sndCorrect = () => { beep(523, 0.12, "sine", 0.12); setTimeout(() => beep(659, 0.12, "sine", 0.12), 100); setTimeout(() => beep(784, 0.15, "sine", 0.15), 200); setTimeout(() => beep(1047, 0.2, "sine", 0.12), 300); };
const sndWrong = () => { beep(300, 0.15, "sawtooth", 0.08); setTimeout(() => beep(250, 0.2, "sawtooth", 0.08), 150); };
const sndExplore = () => { beep(440, 0.06); setTimeout(() => beep(554, 0.06), 60); setTimeout(() => beep(659, 0.08), 120); };
const sndAchieve = () => { [523,659,784,1047,784,1047].forEach((f,i) => setTimeout(() => beep(f, 0.12, "sine", 0.1), i*80)); };

